mapper.insert:
INSERT INTO admin_mobile_device (
    admin_user_id, vendor, device_token, device_name, push_enabled, last_seen_at
) VALUES (
    #{adminUserId}, #{vendor}, #{deviceToken}, #{deviceName}, #{pushEnabled}, #{lastSeenAt}
)
ON DUPLICATE KEY UPDATE
    device_name = VALUES(device_name),
    push_enabled = VALUES(push_enabled),
    last_seen_at = VALUES(last_seen_at),
    updated_at = CURRENT_TIMESTAMP

mapper.delete:
DELETE FROM admin_mobile_device
WHERE admin_user_id = #{adminUserId}
  AND vendor = #{vendor}
  AND device_token = #{deviceToken}
